import{_ as e,o as i,c as o,a1 as t}from"./chunks/framework.hVCBBfmZ.js";const u=JSON.parse('{"title":"关于我 · About","description":"","frontmatter":{"title":"关于我 · About"},"headers":[],"relativePath":"about.md","filePath":"about.md"}'),s={name:"about.md"};function n(l,a,p,r,d,c){return i(),o("div",null,[...a[0]||(a[0]=[t('<div class="about-page"><p class="about-intro"><em>用技术打磨产品，用脚步丈量山野。</em><br><em>Building apps, chasing summits.</em></p><div class="about-section"><h3 id="🙋-你好-hi" tabindex="-1">🙋 你好 / Hi <a class="header-anchor" href="#🙋-你好-hi" aria-label="Permalink to &quot;🙋 你好 / Hi&quot;">​</a></h3><p>我是风行，iOS 独立开发者，base 北京。球场上热衷抢篮板，山野里是个独行者。相信好的产品值得反复打磨，好的风景值得走很远的路去看。如果有一天不上班了，就骑上小摩托去更远的地方。</p><p>I&#39;m Feng Xing, an indie iOS developer based in Beijing. I crash the boards on the court and walk ridgelines solo in the mountains. Great products take iteration; great views take the long trail. One day I&#39;ll trade the desk for a motorcycle and ride somewhere far.</p></div><div class="about-section"><h3 id="🚀-在做什么-building" tabindex="-1">🚀 在做什么 / Building <a class="header-anchor" href="#🚀-在做什么-building" aria-label="Permalink to &quot;🚀 在做什么 / Building&quot;">​</a></h3><p>独立开发面向全球市场的移动应用，从产品设计到 UI/UE，再到代码，再到推广，一人全栈出海。</p><p>Solo indie dev shipping mobile apps to the global market — from design to code to launch.</p></div><div class="about-section"><h3 id="💡-理念-philosophy" tabindex="-1">💡 理念 / Philosophy <a class="header-anchor" href="#💡-理念-philosophy" aria-label="Permalink to &quot;💡 理念 / Philosophy&quot;">​</a></h3><p>对技术追求完美，但更在意屏幕另一边的人用起来是否顺手。如果你对我的 App 有建议，或只是想说声 hi，随时给我发邮件。</p><p>I chase clean code, but I care more about the person on the other side of the screen. Have a suggestion? Just want to say hi? Drop me an email anytime.</p></div><div class="about-section"><h3 id="📬-联系-get-in-touch" tabindex="-1">📬 联系 / Get in Touch <a class="header-anchor" href="#📬-联系-get-in-touch" aria-label="Permalink to &quot;📬 联系 / Get in Touch&quot;">​</a></h3><ul><li>📧 <a href="mailto:bj.lijingcheng@gmail.com" target="_blank" rel="noreferrer">bj.lijingcheng@gmail.com</a></li><li>𝕏 @ljngchng568595</li><li>📕 小红书：532631051</li></ul></div><div class="about-section"><h3 id="📱-我的-app-my-apps" tabindex="-1">📱 我的 App / My Apps <a class="header-anchor" href="#📱-我的-app-my-apps" aria-label="Permalink to &quot;📱 我的 App / My Apps&quot;">​</a></h3><div class="app-list"><div class="app-card placeholder"><span class="app-icon">📱</span><span class="app-name">Coming Soon</span></div><div class="app-card placeholder"><span class="app-icon">✨</span><span class="app-name">Coming Soon</span></div></div></div></div>',1)])])}const m=e(s,[["render",n]]);export{u as __pageData,m as default};
